#include <stdio.h>

// Function Declaration
int factorial(int n);
void countCalls();

int main() {
    int num = 5;

    printf("Calculating factorial of %d...\n", num);
    int result = factorial(num);
    printf("Factorial of %d is %d\n", num, result);

    printf("\n--- Testing Static Variable ---\n");
    countCalls();
    countCalls();
    countCalls();

    return 0;
}

// Recursive Function Definition
int factorial(int n) {
    if (n <= 1)
        return 1;
    else
        return n * factorial(n - 1);
}

// Static Variable Demo
void countCalls() {
    // Static variable is initialized only ONCE
    // It keeps its value between calls
    static int count = 0;
    count++;
    printf("This function has been called %d times\n", count);
}
